with open('/app/image.ppm') as f:
    lines = f.readlines()

w, h = 2400, 1800

pixels = []
for line in lines[4:]:
    vals = line.strip().split()
    for i in range(0, len(vals), 3):
        if i+2 < len(vals):
            pixels.append((int(vals[i]), int(vals[i+1]), int(vals[i+2])))

# Let's look at the image as a whole - sample every Nth pixel
# to understand the structure
print('=== Full image scan (every 10th row, every 10th col) ===')
for r in range(0, h, 10):
    row_str = ''
    for c in range(0, w, 10):
        idx = r * w + c
        rv, gv, bv = pixels[idx]
        # Simple brightness-based char
        brightness = (rv + gv + bv) / 3
        if brightness > 200:
            row_str += '.'
        elif brightness > 150:
            row_str += ':'
        elif brightness > 100:
            row_str += '-'
        elif brightness > 50:
            row_str += '+'
        else:
            row_str += '#'
    print(f'{r:4d} |{row_str}|')
" 2>&1
